// Generated by Cursor AI for jjmil on 2026-03-12.
// Adds a visible highlight when this UI element is focused by controller/keyboard navigation.

using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Shows a visual highlight when this element is the EventSystem's current selection
/// (controller/keyboard focus). Makes it clear which item is selected when navigating
/// with a gamepad or keyboard.
/// </summary>
[RequireComponent(typeof(Selectable))]
public sealed class ControllerFocusHighlight : MonoBehaviour
{
    [Tooltip("Optional: Image or GameObject to show when focused. If null, a simple overlay is created at runtime.")]
    [SerializeField] private GameObject focusHighlight;

    [Tooltip("Color for the auto-created highlight overlay (when focusHighlight is null).")]
    [SerializeField] private Color highlightColor = new Color(1f, 0.9f, 0.4f, 0.25f);

    private Selectable _selectable;
    private GameObject _runtimeHighlight;
    private EventSystem _eventSystem;

    private void Awake()
    {
        _selectable = GetComponent<Selectable>();
        _eventSystem = EventSystem.current;
    }

    private void OnEnable()
    {
        EnsureHighlightExists();
    }

    private void LateUpdate()
    {
        bool focused = IsFocused();
        SetHighlightVisible(focused);
    }

    private bool IsFocused()
    {
        if (_eventSystem == null)
        {
            _eventSystem = EventSystem.current;
        }

        if (_eventSystem == null || _selectable == null)
        {
            return false;
        }

        GameObject selected = _eventSystem.currentSelectedGameObject;
        if (selected == null)
        {
            return false;
        }

        return selected == _selectable.gameObject || selected.transform.IsChildOf(transform);
    }

    private void EnsureHighlightExists()
    {
        if (focusHighlight != null)
        {
            return;
        }

        if (_runtimeHighlight != null)
        {
            return;
        }

        RectTransform rect = transform as RectTransform;
        if (rect == null)
        {
            return;
        }

        var go = new GameObject("ControllerFocusHighlight");
        go.transform.SetParent(transform, worldPositionStays: false);

        RectTransform highlightRect = go.AddComponent<RectTransform>();
        highlightRect.anchorMin = Vector2.zero;
        highlightRect.anchorMax = Vector2.one;
        highlightRect.offsetMin = Vector2.zero;
        highlightRect.offsetMax = Vector2.zero;
        highlightRect.SetAsLastSibling();

        Image img = go.AddComponent<Image>();
        img.color = highlightColor;
        img.raycastTarget = false;
        img.sprite = CreateWhiteSprite();

        _runtimeHighlight = go;
        go.SetActive(false);
    }

    private static Sprite CreateWhiteSprite()
    {
        var tex = new Texture2D(1, 1);
        tex.SetPixel(0, 0, Color.white);
        tex.Apply();
        return Sprite.Create(tex, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f));
    }

    private void SetHighlightVisible(bool visible)
    {
        GameObject target = focusHighlight != null ? focusHighlight : _runtimeHighlight;
        if (target != null)
        {
            target.SetActive(visible);
        }
    }
}
